#include <stdio.h>

int main(void) {
    int start, end;
    scanf("%d %d", &start, &end);

    int min = (start < end) ? start : end;
    int max = (start < end) ? end : start;

    int sum = 0;
    for (int i = min; i <= max; i++) {
        if (i % 2 == 0) {
            sum += i;
        }
    }

    printf("%d\n", sum);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    for (int i = n; i > 0; i--) {
        if (i % 5 == 0) {
            break;
        }
        printf("%d\n", i);
    }

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char password[100];
    scanf("%s", password);

    int length = strlen(password);
    int has_digit = 0;

    for (int i = 0; password[i] != '\0'; i++) {
        if (isdigit(password[i])) {
            has_digit = 1;
            break;
        }
    }

    if (length >= 8 && has_digit) {
        printf("Strong\n");
    } else {
        printf("Weak\n");
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    int score;
    int count_a = 0, count_b = 0, count_c = 0, count_d = 0, count_f = 0;
    char first_grade = '\0';
    int first = 1;

    while (scanf("%d", &score) == 1) {
        char grade;
        if (score >= 90) {
            grade = 'A';
            count_a++;
        } else if (score >= 80) {
            grade = 'B';
            count_b++;
        } else if (score >= 70) {
            grade = 'C';
            count_c++;
        } else if (score >= 60) {
            grade = 'D';
            count_d++;
        } else {
            grade = 'F';
            count_f++;
        }

        if (first) {
            first_grade = grade;
            first = 0;
        }
    }

    printf("%c\n", first_grade);
    printf("A: %d\n", count_a);
    printf("B: %d\n", count_b);
    printf("C: %d\n", count_c);
    printf("D: %d\n", count_d);
    printf("F: %d\n", count_f);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    int count = 0;
    for (int i = 1; i <= n; i++) {
        if (n % i == 0) {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    int sum = 0;
    int temp = n;

    do {
        int digit = temp % 10;
        sum += digit;
        temp /= 10;
    } while (temp > 0);

    printf("%d\n", sum);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (i % 2 == 1 && j % 2 == 1) {
                printf("%d ", i * j);
            }
        }
        printf("\n");
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    if (n <= 0) {
        return 0;
    }

    int a = 0, b = 1;
    printf("%d\n", a);

    for (int i = 1; i < n; i++) {
        printf("%d\n", b);
        int temp = a + b;
        a = b;
        b = temp;
    }

    return 0;
}

#include <stdio.h>
#include <ctype.h>
#include <string.h>

int main(void) {
    char word[100];
    scanf("%s", word);

    int count = 0;
    for (int i = 0; word[i] != '\0'; i++) {
        char c = tolower(word[i]);
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    while (n > 0) {
        int digit = n % 10;
        printf("%d\n", digit);
        n /= 10;
    }

    return 0;
}
